/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
// Exports the contents of a grid (using the selected order and filters) to a PDF file. &IsAuthorized = SecGAMIsAuthByFunctionalityKey.Udp(!'<Check_Is_Authenticated>') If &IsAuthorized
LoadWWPContext.Call(&Context)
Do 'LoadGridState'
&Title = "Fila Impressao"
//Report Template Source Header if &Context.EmpCod = 0 loadWWPContext.Call(&Context) Endif
For Each ORder EmpCod, FilCod Where EmpCod = &Context.EmpCod Where FilCod = &Context.FilCod &AppName = FilFan
&AddressLine1 = &Today.ToFormattedString() + ' ' + &Time.Trim() //FilLogNro.Trim() + ' - ' + FilBai.Trim() + ', '+ FilCidCodNomUfe.Trim()
&AddressLine2 = FilFonNum.Trim() if not FilEml.IsEmpty() if not &AddressLine2.IsEmpty() &AddressLine2 += ' / ' Endif &AddressLine2 += FilEml.Trim() Endif Exit EndFor
Print printTitle End
Do 'PrintFilters'
Do 'PrintColumnTitles'
Do 'PrintData'
Do 'PrintFooter'
EndIf
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
Sub 'PrintFilters'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
If not &FiUsuCod.IsEmpty()
print printBlockFilterFiUsuCod EndIf If not &FIempCod.IsEmpty() print printBlockFilterFIempCod EndIf If not &FIsts.IsEmpty() &FilterFIstsValueDescription = '' Do Case Case &FIsts.ToString().Trim() = !"P" &FilterFIstsValueDescription = "PENDENTE"
Case &FIsts.ToString().Trim() = !"F" &FilterFIstsValueDescription = "FINALIZADO"
Case &FIsts.ToString().Trim() = !"C" &FilterFIstsValueDescription = "CANCELADO/ERRO"
EndCase
print printBlockFilterFIsts EndIf If &GridState.DynamicFilters.Count >= 1 &GridStateDynamicFilter = &GridState.DynamicFilters.Item(1) &DynamicFiltersSelector1 = &GridStateDynamicFilter.Selected Do Case Case &DynamicFiltersSelector1 = !'FIDTAEMS' &FiDtaEms1.FromString(&GridStateDynamicFilter.Value) &FiDtaEms_To1.FromString(&GridStateDynamicFilter.ValueTo) If not &FiDtaEms1.IsEmpty() &FilterFiDtaEmsDescription = "Dta Emissão" &FiDtaEms = &FiDtaEms1 print printBlockFilterFiDtaEms EndIf If not &FiDtaEms_To1.IsEmpty() &FilterFiDtaEmsDescription = format('%1 (%2)', "Dta Emissão", " - ") &FiDtaEms = &FiDtaEms_To1 print printBlockFilterFiDtaEms EndIf Case &DynamicFiltersSelector1 = !'FIDTAINI' &FiDtaIni1.FromString(&GridStateDynamicFilter.Value) &FiDtaIni_To1.FromString(&GridStateDynamicFilter.ValueTo) If not &FiDtaIni1.IsEmpty() &FilterFiDtaIniDescription = "Dta Inicio" &FiDtaIni = &FiDtaIni1 print printBlockFilterFiDtaIni EndIf If not &FiDtaIni_To1.IsEmpty() &FilterFiDtaIniDescription = format('%1 (%2)', "Dta Inicio", " - ") &FiDtaIni = &FiDtaIni_To1 print printBlockFilterFiDtaIni EndIf Case &DynamicFiltersSelector1 = !'FIDTAFIM' &FiDtaFim1.FromString(&GridStateDynamicFilter.Value) &FiDtaFim_To1.FromString(&GridStateDynamicFilter.ValueTo) If not &FiDtaFim1.IsEmpty() &FilterFiDtaFimDescription = "Dta Fim" &FiDtaFim = &FiDtaFim1 print printBlockFilterFiDtaFim EndIf If not &FiDtaFim_To1.IsEmpty() &FilterFiDtaFimDescription = format('%1 (%2)', "Dta Fim", " - ") &FiDtaFim = &FiDtaFim_To1 print printBlockFilterFiDtaFim EndIf EndCase If &GridState.DynamicFilters.Count >= 2 &DynamicFiltersEnabled2 = True &GridStateDynamicFilter = &GridState.DynamicFilters.Item(2) &DynamicFiltersSelector2 = &GridStateDynamicFilter.Selected Do Case Case &DynamicFiltersSelector2 = !'FIDTAEMS' &FiDtaEms2.FromString(&GridStateDynamicFilter.Value) &FiDtaEms_To2.FromString(&GridStateDynamicFilter.ValueTo) If not &FiDtaEms2.IsEmpty() &FilterFiDtaEmsDescription = "Dta Emissão" &FiDtaEms = &FiDtaEms2 print printBlockFilterFiDtaEms EndIf If not &FiDtaEms_To2.IsEmpty() &FilterFiDtaEmsDescription = format('%1 (%2)', "Dta Emissão", " - ") &FiDtaEms = &FiDtaEms_To2 print printBlockFilterFiDtaEms EndIf Case &DynamicFiltersSelector2 = !'FIDTAINI' &FiDtaIni2.FromString(&GridStateDynamicFilter.Value) &FiDtaIni_To2.FromString(&GridStateDynamicFilter.ValueTo) If not &FiDtaIni2.IsEmpty() &FilterFiDtaIniDescription = "Dta Inicio" &FiDtaIni = &FiDtaIni2 print printBlockFilterFiDtaIni EndIf If not &FiDtaIni_To2.IsEmpty() &FilterFiDtaIniDescription = format('%1 (%2)', "Dta Inicio", " - ") &FiDtaIni = &FiDtaIni_To2 print printBlockFilterFiDtaIni EndIf Case &DynamicFiltersSelector2 = !'FIDTAFIM' &FiDtaFim2.FromString(&GridStateDynamicFilter.Value) &FiDtaFim_To2.FromString(&GridStateDynamicFilter.ValueTo) If not &FiDtaFim2.IsEmpty() &FilterFiDtaFimDescription = "Dta Fim" &FiDtaFim = &FiDtaFim2 print printBlockFilterFiDtaFim EndIf If not &FiDtaFim_To2.IsEmpty() &FilterFiDtaFimDescription = format('%1 (%2)', "Dta Fim", " - ") &FiDtaFim = &FiDtaFim_To2 print printBlockFilterFiDtaFim EndIf EndCase If &GridState.DynamicFilters.Count >= 3 &DynamicFiltersEnabled3 = True &GridStateDynamicFilter = &GridState.DynamicFilters.Item(3) &DynamicFiltersSelector3 = &GridStateDynamicFilter.Selected Do Case Case &DynamicFiltersSelector3 = !'FIDTAEMS' &FiDtaEms3.FromString(&GridStateDynamicFilter.Value) &FiDtaEms_To3.FromString(&GridStateDynamicFilter.ValueTo) If not &FiDtaEms3.IsEmpty() &FilterFiDtaEmsDescription = "Dta Emissão" &FiDtaEms = &FiDtaEms3 print printBlockFilterFiDtaEms EndIf If not &FiDtaEms_To3.IsEmpty() &FilterFiDtaEmsDescription = format('%1 (%2)', "Dta Emissão", " - ") &FiDtaEms = &FiDtaEms_To3 print printBlockFilterFiDtaEms EndIf Case &DynamicFiltersSelector3 = !'FIDTAINI' &FiDtaIni3.FromString(&GridStateDynamicFilter.Value) &FiDtaIni_To3.FromString(&GridStateDynamicFilter.ValueTo) If not &FiDtaIni3.IsEmpty() &FilterFiDtaIniDescription = "Dta Inicio" &FiDtaIni = &FiDtaIni3 print printBlockFilterFiDtaIni EndIf If not &FiDtaIni_To3.IsEmpty() &FilterFiDtaIniDescription = format('%1 (%2)', "Dta Inicio", " - ") &FiDtaIni = &FiDtaIni_To3 print printBlockFilterFiDtaIni EndIf Case &DynamicFiltersSelector3 = !'FIDTAFIM' &FiDtaFim3.FromString(&GridStateDynamicFilter.Value) &FiDtaFim_To3.FromString(&GridStateDynamicFilter.ValueTo) If not &FiDtaFim3.IsEmpty() &FilterFiDtaFimDescription = "Dta Fim" &FiDtaFim = &FiDtaFim3 print printBlockFilterFiDtaFim EndIf If not &FiDtaFim_To3.IsEmpty() &FilterFiDtaFimDescription = format('%1 (%2)', "Dta Fim", " - ") &FiDtaFim = &FiDtaFim_To3 print printBlockFilterFiDtaFim EndIf EndCase EndIf EndIf EndIf
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'PrintColumnTitles'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
print printBlockBeforeGrid print printBlockLines_titles
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'PrintData'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
For each order FIempCod FIcod (FiDtaFim) when &OrderedBy = 1 order FIcod when &OrderedBy = 2 AND &OrderedDsc = False order (FIcod) when &OrderedBy = 2 AND &OrderedDsc = True order FIsts when &OrderedBy = 3 AND &OrderedDsc = False order (FIsts) when &OrderedBy = 3 AND &OrderedDsc = True order FIimpPC when &OrderedBy = 4 AND &OrderedDsc = False order (FIimpPC) when &OrderedBy = 4 AND &OrderedDsc = True order FIimpTip when &OrderedBy = 5 AND &OrderedDsc = False order (FIimpTip) when &OrderedBy = 5 AND &OrderedDsc = True order FImsg when &OrderedBy = 6 AND &OrderedDsc = False order (FImsg) when &OrderedBy = 6 AND &OrderedDsc = True order FIrelNam when &OrderedBy = 7 AND &OrderedDsc = False order (FIrelNam) when &OrderedBy = 7 AND &OrderedDsc = True order FiPedCod when &OrderedBy = 8 AND &OrderedDsc = False order (FiPedCod) when &OrderedBy = 8 AND &OrderedDsc = True order FiNfeCod when &OrderedBy = 9 AND &OrderedDsc = False order (FiNfeCod) when &OrderedBy = 9 AND &OrderedDsc = True order FiDtaIni when &OrderedBy = 10 AND &OrderedDsc = False order (FiDtaIni) when &OrderedBy = 10 AND &OrderedDsc = True order FiDtaEms when &OrderedBy = 11 AND &OrderedDsc = False order (FiDtaEms) when &OrderedBy = 11 AND &OrderedDsc = True
using DSWWFilaImpressao(&FiUsuCod, &FIempCod, &FIsts, &DynamicFiltersSelector1, &FiDtaEms1, &FiDtaEms_To1 , &FiDtaIni1, &FiDtaIni_To1, &FiDtaFim1, &FiDtaFim_To1, &DynamicFiltersEnabled2, &DynamicFiltersSelector2 , &FiDtaEms2, &FiDtaEms_To2, &FiDtaIni2, &FiDtaIni_To2, &FiDtaFim2, &FiDtaFim_To2 , &DynamicFiltersEnabled3, &DynamicFiltersSelector3, &FiDtaEms3, &FiDtaEms_To3, &FiDtaIni3, &FiDtaIni_To3 , &FiDtaFim3, &FiDtaFim_To3) &FIstsDescription = '' Do Case Case FIsts.ToString().Trim() = !"P" &FIstsDescription = "PENDENTE"
Case FIsts.ToString().Trim() = !"F" &FIstsDescription = "FINALIZADO"
Case FIsts.ToString().Trim() = !"C" &FIstsDescription = "CANCELADO/ERRO"
EndCase
Do 'BeforePrintLine' print printBlockLines_data Do 'AfterPrintLine' EndFor
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'LoadGridState'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
// Load grid state from session. If &Session.Get(!"WWFilaImpressaoGridState") = !"" &GridState.FromXml(LoadGridState.Udp(!"WWFilaImpressaoGridState")) Else &GridState.FromXml(&Session.Get(!"WWFilaImpressaoGridState")) Endif
&OrderedBy = &GridState.OrderedBy &OrderedDsc = &GridState.OrderedDsc
For &GridStateFilterValue in &GridState.FilterValues Do Case Case &GridStateFilterValue.Name = !"FIUSUCOD" &FiUsuCod.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"FIEMPCOD" &FIempCod.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"FISTS" &FIsts.FromString(&GridStateFilterValue.Value) EndCase EndFor
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
